**Example (JavaScript):**
```javascript
// JavaScript (Duck Typing)
function makeSound(creature) {
  // We don't check if 'creature' is a Dog or a Cat class.
  // We just check if it has a 'quack' method.
  if (typeof creature.quack === 'function') {
    creature.quack();
  }
}

**Example:**
```typescript
// Define an interface (the "Duck" shape)
interface Duck {
  quack(): void;
  swim(): void;
}

// Function expects a Duck
function feed(d: Duck) {
  d.quack();
  d.swim();
}

// Object A: Explicitly typed as Duck
const realDuck: Duck = {
  quack: () => console.log("Quack"),
  swim: () => console.log("Swimming")
};

// Object B: Just a plain object, but has the same shape
const rubberDuck = {
  quack: () => console.log("Squeak"),
  swim: () => console.log("Floating")
};

// TypeScript accepts rubberDuck because it "looks like a duck"
feed(realDuck);   // ✅ OK
feed(rubberDuck); // ✅ OK (Duck Typing in action!)

// Object C: Missing a property
const brokenDuck = {
  quack: () => console.log("Quack")
  // Missing 'swim'
};

